using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 breaking change: discriminator property renamed from
            // "Discriminator" to "$type". Revert to old name for compatibility
            // with 500K existing documents and direct SQL queries.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 breaking change: id format changed from "EntityName|KeyValue"
            // to just "KeyValue". Revert to old format for existing documents.
            entity.HasKey(p => p.Id);
            entity.Property(p => p.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();

            // EF Core 9 removed support for client-side Cosmos indexes (HasIndex).
            // Define indexes via Azure Portal, Bicep/ARM, or the Cosmos SDK instead.
        });
    }
}

