class CosmosQuery
{
    // EF Core 9 breaking change: synchronous I/O is no longer supported for Cosmos.
    // All queries must use async APIs (ToListAsync, FirstOrDefaultAsync, etc.).
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we kept "Discriminator" property name
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // Converted from sync .ToList() to async .ToListAsync()
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

